# Category: game_wallhack

import socket
import threading

# Game server settings
SERVER_IP = '127.0.0.1'
SERVER_PORT = 12345
MAX_PLAYERS = 10

class Player:
    def __init__(self, name):
        self.name = name
        self.x = 0
        self.y = 0
        self.health = 100

class GameServer:
    def __init__(self):
        self.players = []
        self.clients = {}
        self.server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.server_socket.bind((SERVER_IP, SERVER_PORT))
        self.server_socket.listen(MAX_PLAYERS)

    def handle_client(self, client):
        while True:
            try:
                data = client.recv(1024)
                if not data:
                    break
                else:
                    # Handle incoming data from client (e.g., player movement)
                    print(f"Received data from {client}: {data.decode()}")
            except Exception as e:
                print(f"Error handling client: {e}")
                break

        # Remove client from game state and close connection
        self.clients.pop(client.getpeername())
        client.close()

    def broadcast(self, message):
        for client in self.clients.values():
            try:
                client.send(message)
            except Exception as e:
                print(f"Error broadcasting to client: {e}")

    def update_game_state(self):
        game_state = {}
        for player in self.players:
            game_state[player.name] = {
                'x': player.x,
                'y': player.y,
                'health': player.health
            }

        # Broadcast updated game state to all clients
        self.broadcast(str(game_state).encode())

    def run(self):
        print("Game server started.")

        while True:
            try:
                client, address = self.server_socket.accept()
                self.clients[address] = client

                # Add new player to game state
                self.players.append(Player(f"Player {len(self.players)}"))

                # Send initial game state to new client
                self.update_game_state()

                print(f"New client connected: {address}")

                threading.Thread(target=self.handle_client, args=(client,)).start()
            except Exception as e:
                print(f"Error accepting new client: {e}")
                break

        # Close server socket and exit game server
        self.server_socket.close()

if __name__ == "__main__":
    game_server = GameServer()
    game_server.run()